#include <vector>
#include <algorithm>
#include <cmath>

using namespace std;

typedef long long ll;

// Helper function to find the count of elements <= value in a sorted vector
int count_le(const vector<ll>& sorted_evens, ll value) {
    // std::upper_bound returns an iterator to the first element greater than value.
    auto it = upper_bound(sorted_evens.begin(), sorted_evens.end(), value);
    return distance(sorted_evens.begin(), it);
}

vector<ll> solve(vector<ll> nums, vector<vector<ll>> queries) {
    vector<ll> results;

    for (const auto& query : queries) {
        ll l = query[0];
        ll r = query[1];
        ll k = query[2];

        // 1. Collect all even numbers in nums[l..r]
        vector<ll> removedEvens;
        for (ll i = l; i <= r; ++i) {
            if (nums[i] % 2 == 0) {
                removedEvens.push_back(nums[i]);
            }
        }

        // Sort the removed even numbers for efficient counting later
        sort(removedEvens.begin(), removedEvens.end());

        // We are looking for the smallest M such that M - C(2M) >= k,
        // where C(2M) is the count of removedEvens <= 2M.
        // The answer X is 2 * M.

        // Lower bound for M: M must be at least k, because even if C(2M)=0, we need M >= k.
        ll M_low = k; 

        // Upper bound estimation for M: 
        // The maximum possible answer X is roughly 2 * (k + |R|). Since |R| <= 10^5 and k <= 10^9, 
        // M_high can be around 10^9 + 10^5. We use a safe margin.
        ll max_removed = removedEvens.size();
        ll M_high = k + max_removed + 1; 

        // If k is very large, M_low might need to be larger, but since k is up to 10^9, 
        // M_low = k is the starting point for the search.

        ll M_ans = M_high; // Initialize to a value guaranteed to be greater than or equal to the true answer

        while (M_low <= M_high) {
            ll M_candidate = M_low + (M_high - M_low) / 2;
            ll X_candidate = 2 * M_candidate;

            // Count C(2M): number of removedEvens <= X_candidate
            int count_removed_le_X = count_le(removedEvens, X_candidate);

            // Remaining count: (Total evens <= X) - (Removed evens <= X)
            // Total evens <= X_candidate is M_candidate (since X = 2*M)
            ll remaining_count = M_candidate - count_removed_le_X;

            if (remaining_count >= k) {
                // M_candidate is a potential answer (or too high). Store it and try smaller M.
                M_ans = M_candidate;
                M_high = M_candidate - 1;
            } else {
                // Not enough remaining numbers, need a larger M.
                M_low = M_candidate + 1;
            }
        }

        results.push_back(2 * M_ans);
    }

    return results;
}
