    // The problem asks for the k-th smallest positive even number
    // after removing all even numbers present in nums[l..r].
    // The sequence of positive even numbers is 2, 4, 6, 8, 10, 12, ...
    // The i-th positive even number is 2 * i.

    // For a given query [l, r, k]:
    // 1. Identify all even numbers in nums[l..r].
    // 2. Count how many such even numbers there are. Let this count be 'removed_count'.
    // 3. The original sequence is 2, 4, 6, ..., 2*k, ...
    // 4. The target is the k-th smallest remaining even number.
    //
    // Let E be the set of all positive even numbers: E = {2, 4, 6, 8, ...}
    // Let R be the set of removed even numbers: R = {x in nums[l..r] | x is even}
    // The remaining set is E \ R.
    // We are looking for the k-th element of E \ R when sorted.

    // The original k-th smallest even number is 2 * k.
    // If 'removed_count' numbers smaller than or equal to 2 * k were removed,
    // then the k-th smallest remaining number will be larger than 2 * k,
    // or it might be 2 * k itself if none of the removed numbers were <= 2 * k.

    // More precisely:
    // Let C(X) be the count of elements in R that are less than or equal to X.
    // The number of elements in E \ R less than or equal to X is (X/2) - C(X).
    // We are looking for the smallest integer X (which must be even) such that:
    // (X/2) - C(X) >= k
    // (X/2) - C(X) = k  (Since we look for the k-th smallest)

    // Since the required number X must be even, let X = 2 * M.
    // The condition becomes: M - C(2M) = k, or M = k + C(2M).

    // C(2M) is the count of even numbers in nums[l..r] that are <= 2M.
    // Since nums is strictly increasing, we can efficiently count this.
    // We need to find M such that M - (count of even numbers in nums[l..r] <= 2M) = k.

    for (const query of queries) {
        const [l, r, k] = query;

        // 1. Collect all even numbers in nums[l..r]
        const removedEvens = [];
        for (let i = l; i <= r; i++) {
            if (nums[i] % 2 === 0) {
                removedEvens.push(nums[i]);
            }
        }

        // 2. Determine the count C(X) dynamically.
        // We are looking for the smallest even number X = 2M such that
        // (M - count of removedEvens <= X) = k.

        // The answer X must be at least 2 * k.
        let low = 2 * k;
        // A safe upper bound. Max nums[i] is 10^9. Max k is 10^9.
        // The answer could potentially be around 2 * 10^9 + |R|, so 3 * 10^9 is safe for initial guess.
        let high = 4 * 10**9; // Sufficiently large upper bound
        let ans_X = high;

        // Binary search for the smallest even number X (represented by M = X/2)
        while (low <= high) {
            // Search space for M = X/2
            const M_candidate = Math.floor((low / 2) + (high / 2)) / 2;
            const X_candidate = 2 * M_candidate;

            // Count how many removedEvens are <= X_candidate
            let count_removed_le_X = 0;
            for (const r_even of removedEvens) {
                if (r_even <= X_candidate) {
                    count_removed_le_X++;
                } else {
                    // Since removedEvens are not necessarily sorted, we must check all.
                    // However, if we sort removedEvens first, we can optimize this.
                }
            }

            // Optimization: Sort removedEvens once per query.
            // This significantly speeds up counting inside the BS loop.
        }

        // Re-implementing the loop with sorting for efficiency
        removedEvens.sort((a, b) => a - b);

        // Binary search for M = X/2
        let M_low = k; // Minimum M such that M >= k
        let M_high = 2 * 10**9 + removedEvens.length + 2; // A safe upper bound for M
        let M_ans = M_high;

        while (M_low <= M_high) {
            const M_candidate = Math.floor((M_low + M_high) / 2);
            const X_candidate = 2 * M_candidate;

            // Count how many removedEvens are <= X_candidate using binary search (upper_bound equivalent)
            let count_removed_le_X = 0;

            // Find the index of the last element in removedEvens that is <= X_candidate
            let low_idx = 0;
            let high_idx = removedEvens.length - 1;
            let boundary = -1;

            while (low_idx <= high_idx) {
                const mid_idx = Math.floor((low_idx + high_idx) / 2);
                if (removedEvens[mid_idx] <= X_candidate) {
                    boundary = mid_idx;
                    low_idx = mid_idx + 1;
                } else {
                    high_idx = mid_idx - 1;
                }
            }

            count_removed_le_X = boundary + 1;

            // Check the condition: M - C(2M) >= k
            const remaining_count = M_candidate - count_removed_le_X;

            if (remaining_count >= k) {
                // This M_candidate might be the answer, try smaller M
                M_ans = M_candidate;
                M_high = M_candidate - 1;
            } else {
                // Not enough remaining numbers, need larger M
                M_low = M_candidate + 1;
            }
        }

        results.push(2 * M_ans);
    }

    return results;
